window.COUNTRY = {"name":"Singapore","code":"sg","tagline":"Advanced fabs, semiconductor equipment & HQ hub — the high-value front of the SE-Asia chip chain.","macro":[{"key":"gdp","k":"GDP growth","v":"+4.8%","as_of":"2025","source":"MTI","glo":"GDP growth","basis":"YoY","view":{"metric":"value","ref":0,"good":"high"},"series":[["2021",9.7],["2022",3.8],["2023",1.1],["2024",4.4],["2025",4.8]]},{"key":"cpi","k":"Core CPI","v":"+1.0%","as_of":"2025","source":"MAS","glo":"Core CPI","basis":"YoY","view":{"metric":"value","ref":0,"good":"band","band":[0.5,2.5]},"series":[["2021",0.9],["2022",4.1],["2023",4.2],["2024",2.8],["2025",1.0]]},{"key":"nodx","k":"NODX","v":"+4.8%","as_of":"2025","source":"Enterprise SG","glo":"NODX","basis":"YoY","view":{"metric":"value","ref":0,"good":"high"},"series":[["2021",12.0],["2022",3.0],["2023",-13.1],["2024",0.2],["2025",4.8]]},{"key":"unemp","k":"Unemployment","v":"1.9%","as_of":"2025","source":"MOM","glo":"Unemployment","view":{"metric":"value","ref":2.5,"good":"low"},"series":[["2021",2.7],["2022",2.1],["2023",1.9],["2024",1.9],["2025",1.9]]},{"key":"epmi","k":"Electronics PMI","v":"50.9","as_of":"Dec 2025","source":"SIPMM","glo":"Electronics PMI","view":{"metric":"value","ref":50,"good":"high"},"series":[["Dec 2025",50.9]]}],"role":[{"node":"Semiconductor equipment","scope":"global output","share":20,"disp":"~20%","type":"hold","source":"A*STAR / industry","year":"2024","glo":"Semiconductor equipment"},{"node":"Semiconductor output","scope":"global total","share":10,"disp":"~10%","type":"hold","source":"A*STAR","year":"2024","glo":"Wafer fab"},{"node":"Wafer fab capacity","scope":"mature / specialty","share":5,"disp":"~5%","type":"hold","source":"A*STAR","year":"2024","glo":"Wafer fab"},{"node":"Leading-edge logic","scope":"≤7nm · GF tops out ~12nm","share":0,"disp":"0%","type":"gap","source":"industry","year":"2024","glo":"leading-edge logic"},{"node":"Advanced memory (HBM)","scope":"design & lead supply elsewhere","share":1,"disp":"~1%","type":"gap","source":"industry","year":"2024","glo":"HBM"}],"role_take":"Singapore is the region's high-value front: ~20% of global semiconductor equipment output, ~10% of world chip output and ~5% of wafer-fab capacity (mature/specialty), plus the equipment that makes chips. It doesn't do leading-edge logic or advanced memory — those stay in Taiwan & Korea.","clusters":[{"seg":"Wafer fabrication (mature / specialty)","level":3,"what":"A top global hub for mature & specialty-node fabs.","anchors":[{"n":"GlobalFoundries","o":"US"},{"n":"UMC","o":"TW"},{"n":"Micron","o":"US"},{"n":"Soitec","o":"FR"},{"n":"Vanguard (VIS)","o":"TW"}]},{"seg":"Semiconductor equipment","level":3,"what":"~20% of global chip-equipment output; a major MNC tool & sub-system base.","anchors":[{"n":"Applied Materials","o":"US"},{"n":"Lam Research","o":"US"},{"n":"ASML","o":"NL"}]},{"seg":"Memory & storage","level":2,"what":"NAND assembly/test plus the data-storage cluster.","anchors":[{"n":"Micron","o":"US"},{"n":"Western Digital","o":"US"},{"n":"Seagate","o":"US"}]},{"seg":"Analog / power / RF","level":2,"what":"MNC fabs and design centres.","anchors":[{"n":"STMicroelectronics","o":"EU"},{"n":"Infineon","o":"DE"},{"n":"NXP","o":"NL"}]}],"valuechain":"High-value front-of-chain for the region — mature/specialty wafer fabs, the equipment that makes chips, and memory/storage; an MNC magnet and regional-HQ base. Net exporter of wafers, equipment & storage.","sourcing":{"buy":["Silicon wafers, gases, chemicals","fab sub-systems & parts","photomasks"],"sell":["Mature/specialty wafers & ICs","semiconductor equipment & parts","NAND / storage devices"]},"glossary":{"GDP growth":"Real gross domestic product growth, year-over-year.","Core CPI":"Core consumer inflation (excludes accommodation & private transport) — MAS's main price gauge.","CPI":"Headline consumer price inflation, year-over-year.","NODX":"Non-Oil Domestic Exports — Singapore's key export gauge (locally-made goods, ex-oil); electronics is a big share.","Electronics PMI":"Electronics-sector Purchasing Managers' Index (SIPMM) — >50 = the chip cluster is expanding.","Unemployment":"Resident unemployment rate (seasonally adjusted).","OPR":"Overnight Policy Rate — Bank Negara Malaysia's benchmark interest rate.","E&E exports":"Electrical & electronics exports — Malaysia's largest export category (~40% of total), incl. semiconductors.","OSAT":"Outsourced Semiconductor Assembly & Test — the chip 'back-end': packaging & testing finished wafers into usable chips.","ATP":"Assembly, Test & Packaging — the semiconductor back-end (same idea as OSAT).","Advanced packaging":"High-density chip packaging (2.5D/3D, chiplets) — where more performance gains now come from; Malaysia is only now building it.","IC design":"Designing the chip itself (the high-value front-of-chain step) — minimal in SE-Asia, which is mostly mid-stream.","Semiconductor equipment":"The tools that make chips (deposition, etch, test handlers) — Singapore is a major production base.","Wafer fab":"Front-end chip fabrication (turning silicon wafers into circuits); SE-Asia runs mainly mature/specialty fabs.","SiC":"Silicon carbide — a wide-bandgap power semiconductor for efficient EV/industrial power electronics.","leading-edge logic":"The most advanced chips (≤7nm) for CPUs/GPUs/AI — fabricated only in Taiwan & Korea, not SE-Asia.","HBM":"High-Bandwidth Memory — stacked DRAM for AI accelerators; designed/made by SK hynix, Samsung & Micron.","substrate":"The package base that connects a chip die to the circuit board — a tight global bottleneck (mostly Japan/Korea/Taiwan)."}};
